        "col1_Assessment attachment^": "川崎地球温暖化対策推進基本計画_第1章.pdf",
        "col2_Assessment direct link^": "https://www.city.kawasaki.jp/300/cmsfiles/contents/0000133/133741/01-1honntai_ver2.pdf",
        "col3_Confirm attachment/link provided to assessment": "The assessment has been attached and can be accessed (unrestricted) on the link provided",
