        "col7_Estimated reduction in annual inventory emissions (metric tonnes CO2e)^^": 2180000.0,
        "col10_Co-benefits realized": "Social: Enhanced resilience to shocks and disasters",
        "col11_Funding source(s)": "Regional funds and programmes|Other: 補助金、交付金|Jurisdiction's own resources",
        "col12_Status of action in the reporting year": "Action in operation (jurisdiction-wide)",
